import './select.css';
import logo from './logo.svg';
import { useState } from 'react';
const SelectContainerHeader = () => {
    console.log('render');
    const name = 'houssem';


    const [x,setX] = useState(0);
    const addPlusOne = () => {
        console.log('function called here',x);
        x = x + 2;


    }





    return (
        <header>
            <nav className='nav-container'>
                <div className="nav-logo">
                    <img src={logo} title='icone' alt='icones' />
                    <h1>TITLE</h1>
                </div>
                <div>
                    <input type="text" name="nav-search" placeholder="search" className="nav-search" />
                    <p>{name + ' ' + 'guizani'}</p>
                </div>
                <div className="nav-button">
                    <button>Login</button>
                    <button>Sign Up</button>
                </div>
                <div>
                    <p>{x}</p>
                    <button id='buttonClick' onClick={addPlusOne}>Click here to add plus one to the varible x</button>
                </div>
            </nav>

        </header>
    );
}



export default SelectContainerHeader;
